head.b:skin:
/*------------------------------------------------------------
PREMIUM NEWS STYLING CORE SYSTEM
------------------------------------------------------------*/
:root {
    --primary-gradient: linear-gradient(135deg, #ff1e56 0%, #ffac41 50%, #3232ff 100%);
    --dark-bg: #030712;
    --dark-card: #0f172a;
    --light-bg: #f8fafc;
    --light-card: #ffffff;
    --text-main: #0f172a;
    --text-muted: #475569;
    --accent-color: #ff1e56;
    --radius-mega: 16px;
    --shadow-mega: 0 20px 40px rgba(15, 23, 42, 0.05);
    --transition: all 0.3s ease;
}

body.dark-mode {
    --light-bg: var(--dark-bg);
    --light-card: var(--dark-card);
    --text-main: #f1f5f9;
    --text-muted: #94a3b8;
}

* { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: 'Plus Jakarta Sans', 'Noto Sans Devanagari', sans-serif; background-color: var(--light-bg); color: var(--text-main); transition: var(--transition); }
a { color: inherit; text-decoration: none; }
img { max-width: 100%; height: auto; display: block; border-radius: 10px; }

.container { max-width: 1300px; margin: 0 auto; padding: 0 20px; }

/* Top Bar Live Ticker */
.top-bar { background: #090d16; color: #fff; padding: 12px 0; font-size: 13px; }
.ticker-wrap { display: flex; align-items: center; justify-content: space-between; }
.ticker-title { background: var(--primary-gradient); padding: 5px 12px; font-weight: 800; border-radius: 6px; margin-right: 15px; white-space: nowrap; }
.ticker-content { display: inline-block; white-space: nowrap; animation: ticker-live 30s linear infinite; font-weight: 700; color: #e2e8f0; }
@keyframes ticker-live { 0% { transform: translate3d(100%, 0, 0); } 100% { transform: translate3d(-100%, 0, 0); } }

/* Elegant Sticky Header Navbar */
header { background: var(--light-card); position: sticky; top: 0; z-index: 999; box-shadow: 0 2px 20px rgba(0,0,0,0.05); padding: 15px 0; border-bottom: 1px solid rgba(0,0,0,0.05); }
.header-inner { display: flex; flex-direction: column; align-items: center; gap: 15px; }
@media(min-width: 992px) { .header-inner { flex-direction: row; justify-content: space-between; } }

.logo-branding h1 { font-size: 38px; font-weight: 800; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; text-transform: uppercase; letter-spacing: -1px; }
.logo-sub { display: block; font-size: 11px; font-weight: 700; color: var(--text-muted); letter-spacing: 4px; text-transform: uppercase; margin-top: 2px; }

nav ul { display: flex; gap: 24px; }
nav ul li a { font-weight: 700; font-size: 15px; color: var(--text-main); padding: 5px 0; }
nav ul li a:hover { color: var(--accent-color); }

.mode-btn { width: 40px; height: 40px; border-radius: 10px; background: var(--light-bg); display: flex; align-items: center; justify-content: center; cursor: pointer; border: 1px solid rgba(0,0,0,0.05); color: var(--text-main); }

/* Grid Structural Split Layout */
.main-wrapper { display: grid; grid-template-columns: 1fr; gap: 40px; margin-top: 40px; }
@media(min-width: 992px) { .main-wrapper { grid-template-columns: 2.5fr 1fr; } }

/* Post Layout System Cards */
.posts-grid { display: grid; grid-template-columns: 1fr; gap: 30px; }
@media(min-width: 650px) { .posts-grid { grid-template-columns: 1fr 1fr; } }

.card { background: var(--light-card); border-radius: var(--radius-mega); overflow: hidden; box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); display: flex; flex-direction: column; height: 100%; transition: var(--transition); }
.card:hover { transform: translateY(-5px); box-shadow: 0 25px 50px rgba(0,0,0,0.08); }
.card-thumb { height: 220px; background: #0f172a; position: relative; }
.card-thumb img { width: 100%; height: 100%; object-fit: cover; }

.badge { position: absolute; top: 15px; left: 15px; background: var(--primary-gradient); color: #fff; padding: 4px 12px; font-size: 11px; font-weight: 800; border-radius: 6px; text-transform: uppercase; }
.card-content { padding: 25px; flex-grow: 1; display: flex; flex-direction: column; justify-content: space-between; }
.card-meta { font-size: 13px; color: var(--text-muted); margin-bottom: 10px; font-weight: 700; }
.card-title { font-size: 20px; font-weight: 800; line-height: 1.4; margin-bottom: 12px; color: var(--text-main); }
.card-text { font-size: 14px; color: var(--text-muted); line-height: 1.6; margin-bottom: 20px; }
.read-btn { font-weight: 800; font-size: 14px; color: var(--accent-color); }

/* Detailed Post Internal Typography */
.post-body-container { background: var(--light-card); padding: 35px; border-radius: var(--radius-mega); box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); }
.post-main-title { font-size: 34px; font-weight: 800; line-height: 1.35; margin-bottom: 20px; color: var(--text-main); }
.post-content-inner { font-size: 17px; line-height: 1.85; color: var(--text-main); }
.post-content-inner p { margin-bottom: 20px; }

/* Sidebar Architectural Components */
.sidebar-pane { display: flex; flex-direction: column; gap: 35px; }
.block-widget { background: var(--light-card); padding: 25px; border-radius: var(--radius-mega); box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); }
.block-title { font-size: 16px; font-weight: 800; text-transform: uppercase; margin-bottom: 20px; padding-bottom: 10px; color: var(--text-main); border-bottom: 2px solid rgba(0,0,0,0.04); position: relative; }
.block-title::after { content: ''; position: absolute; bottom: -2px; left: 0; width: 50px; height: 2px; background: var(--primary-gradient); }

.search-input-group form { display: flex; gap: 8px; }
.search-field { flex-grow: 1; padding: 12px 15px; border: 1px solid rgba(0,0,0,0.08); border-radius: 10px; background: var(--light-bg); color: var(--text-main); font-weight: 600; outline: none; }
.search-go-btn { background: var(--primary-gradient); color: #fff; border: none; padding: 0 18px; border-radius: 10px; font-weight: 800; cursor: pointer; }

.tag-cloud-list { display: flex; flex-wrap: wrap; gap: 8px; }
.tag-cloud-list li a { display: block; background: var(--light-bg); padding: 6px 14px; font-size: 13.5px; font-weight: 700; border-radius: 8px; }

/* Footer Framework */
footer { background: #02050b; color: #94a3b8; padding: 60px 0 30px; margin-top: 80px; border-top: 3px solid var(--accent-color); text-align: center; }
.footer-legal-base { font-size: 14px; font-weight: 700; color: #475569; }
.footer-legal-base a { background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; font-weight: 800; }

body.script:
//
// Mode Switch Logic
const toggleEngineBtn = document.getElementById('dark-mode-engine-btn');
const themeIconSymbol = toggleEngineBtn.querySelector('i');

toggleEngineBtn.addEventListener('click', () => {
    document.body.classList.toggle('dark-mode');
    if(document.body.classList.contains('dark-mode')) {
        themeIconSymbol.className = 'fas fa-sun';
    } else {
        themeIconSymbol.className = 'fas fa-moon';
    }
});
//
